// Script Continued Below
// 2.8   - 2022-04-05 - raj -  STRY0117600 - Update Templates to match the UI of Org Hierarchy 
//                                         - Changes in Server Script, client controller, HTML, UI Script and Template
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
	// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel; declare once as global
	var taskWidgetData = new TaskWidgetData();
	data.baseWidget = (input || {}).baseWidget || (options || {}).baseWidget || undefined;
	data.iconGroup = (input || {}).iconGroup || (options || {}).iconGroup || undefined;

	// todo, figure out how to adjust to know if Org or not

	// if messages not loaded, load messages
	var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages(data.baseWidget);

	main();
	function main() {

		if(input){
			_processInput();
		}// else {
			_initialLoad();
//		}			


		// INPUT GOES HERE


	}

	function _initialLoad(){
		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
		data.messages = taskWidgetIconsAndMessage.loadMessages();
		data.icons = taskWidgetIconsAndMessage.loadIcons();
	}

	function _processInput(){
		if(input.orientationChanged){
			data.orientationChanged = false;
			taskWidgetIconsAndMessage.savePreferenceOrientation(input.settings.treeOrientation);
		} else if(input.percentChanged){
			data.percentChanged = false;
			taskWidgetIconsAndMessage.savePreferencePercent(input.settings.selectPercent);
		} else if(input.favoriteChanged){
			data.favoriteChanged = false;
			taskWidgetIconsAndMessage.savePreferenceFavorite(input.settings.favorite);		
		}	

	}

})($sp, input, data, options, gs);
